1	<!DOCTYPE html>
2	<html lang="ko">
3	<head>
4	  <meta charset="UTF-8">
5	  <meta name="viewport" content="width=device-width, initial-scale=1.0">
6	  <title>TermBase Atlas — 지식의 좌표</title>
7	  <!-- ag-Grid 스타일 -->
8	  <script src="https://cdn.jsdelivr.net/npm/ag-grid-community/dist/ag-grid-community.min.js"></script>
9	  <style>
10	    :root {
11	      /* Atlas v2 Palette - OKLch based */
12	      --bg: oklch(100% 0 0);
13	      --surface: oklch(98.5% 0.005 60);
14	      --surface-hover: oklch(97% 0.008 60);
15	      --fg: oklch(15% 0 0);
16	      --fg-soft: oklch(35% 0.01 60);
17	      --muted: oklch(55% 0.01 60);
18	      --border: oklch(15% 0 0);
19	      --border-lt: oklch(92% 0.01 60);
20	      --accent: oklch(60% 0.15 45);
21	      --accent-soft: oklch(97% 0.02 45);
22	      --shadow-sm: 0 2px 8px rgba(0,0,0,0.04);
23	      --shadow-md: 0 8px 24px rgba(0,0,0,0.08);
24	      
25	      --font: 'Pretendard', -apple-system, BlinkMacSystemFont, system-ui, sans-serif;
26	      --font-display: 'Iowan Old Style', Charter, Georgia, serif;
27	      --mono: 'JetBrains Mono', ui-monospace, Menlo, monospace;
28	      --nav-h: 72px;
29	      --sidebar-w: 280px;
30	      --radius: 8px;
31	    }
32	
33	    [data-theme="dark"] {
34	      --bg: oklch(12% 0 0);
35	      --surface: oklch(16% 0.01 60);
36	      --surface-hover: oklch(19% 0.01 60);
37	      --fg: oklch(98% 0 0);
38	      --fg-soft: oklch(85% 0.01 60);
39	      --muted: oklch(65% 0.01 60);
40	      --border: oklch(98% 0 0);
41	      --border-lt: oklch(25% 0.01 60);
42	      --accent: oklch(70% 0.15 45);
43	      --accent-soft: oklch(22% 0.03 45);
44	      --shadow-sm: 0 2px 8px rgba(0,0,0,0.2);
45	      --shadow-md: 0 8px 32px rgba(0,0,0,0.4);
46	    }
47	
48	    /* Base & Reset */
49	    *, *::before, *::after { box-sizing: border-box; }
50	    body {
51	      margin: 0; background: var(--bg); color: var(--fg);
52	      font-family: var(--font); font-size: 15px; line-height: 1.6;
53	      -webkit-font-smoothing: antialiased; transition: background 0.3s, color 0.3s;
54	    }
55	    a { color: inherit; text-decoration: none; }
56	
57	    /* Nav */
58	    .nav {
59	      position: fixed; top: 0; left: 0; right: 0; height: var(--nav-h);
60	      background: rgba(255, 255, 255, 0.8); backdrop-filter: blur(12px); -webkit-backdrop-filter: blur(12px);
61	      border-bottom: 1.5px solid var(--border-lt); display: flex; align-items: center; padding: 0 32px; z-index: 1000;
62	    }
63	    [data-theme="dark"] .nav { background: rgba(18, 18, 18, 0.8); }
64	    .nav-logo { font-family: var(--font-display); font-size: 24px; font-weight: 800; font-style: italic; }
65	    .nav-logo span { font-style: normal; color: var(--accent); }
66	    .nav-links { display: flex; gap: 32px; margin-left: 48px; }
67	    .nav-link { font-weight: 700; color: var(--muted); transition: color 0.2s; position: relative; }
68	    .nav-link:hover, .nav-link.active { color: var(--fg); }
69	    .nav-link.active::after { content: ''; position: absolute; bottom: -8px; left: 0; right: 0; height: 3px; background: var(--accent); }
70	
71	    .nav-actions { margin-left: auto; display: flex; align-items: center; gap: 20px; }
72	    .theme-toggle {
73	      background: none; border: 1.5px solid var(--border-lt); border-radius: var(--radius);
74	      width: 44px; height: 44px; display: flex; align-items: center; justify-content: center;
75	      cursor: pointer; color: var(--fg); transition: all 0.2s;
76	    }
77	    .theme-toggle:hover { border-color: var(--border); background: var(--surface); }
78	
79	    /* Layout */
80	    .layout { display: grid; grid-template-columns: var(--sidebar-w) 1fr; margin-top: var(--nav-h); min-height: calc(100vh - var(--nav-h)); }
81	
82	    /* Hero */
83	    .hero {
84	      padding: 100px 60px 80px; text-align: center; max-width: 1000px; margin: 0 auto;
85	      border-bottom: 1.5px solid var(--border-lt);
86	    }
87	    .hero h1 { font-family: var(--font-display); font-size: 64px; font-weight: 800; margin-bottom: 24px; letter-spacing: -0.03em; line-height: 1.1; }
88	    .hero p { font-size: 20px; color: var(--fg-soft); margin-bottom: 48px; max-width: 600px; margin-left: auto; margin-right: auto; }
89	    
90	    .search-hero-wrap { position: relative; max-width: 720px; margin: 0 auto; }
91	    .search-hero-wrap input {
92	      width: 100%; padding: 24px 32px 24px 64px; background: var(--surface);
93	      border: 2px solid var(--border-lt); border-radius: 100px; font-size: 20px; font-family: var(--font);
94	      color: var(--fg); outline: none; transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
95	      box-shadow: var(--shadow-sm);
96	    }
97	    .search-hero-wrap input:focus { border-color: var(--accent); background: var(--bg); box-shadow: var(--shadow-md); transform: translateY(-2px); }
98	    .search-hero-wrap svg { position: absolute; left: 24px; top: 50%; transform: translateY(-50%); color: var(--muted); }
99	
100	    /* Sidebar */
101	    .sidebar { border-right: 1.5px solid var(--border-lt); background: var(--bg); position: sticky; top: var(--nav-h); height: calc(100vh - var(--nav-h)); overflow-y: auto; padding: 40px 0; }
102	    .sidebar-section { margin-bottom: 48px; }
103	    .sidebar-title { padding: 0 32px; font-size: 13px; font-weight: 800; text-transform: uppercase; letter-spacing: 0.15em; color: var(--muted); margin-bottom: 20px; }
104	    .cat-item { display: flex; justify-content: space-between; align-items: center; padding: 12px 32px; cursor: pointer; border-left: 4px solid transparent; transition: all 0.2s; font-weight: 600; }
105	    .cat-item:hover { background: var(--surface); }
106	    .cat-item.active { background: var(--accent-soft); border-left-color: var(--accent); color: var(--accent); }
107	    .cat-count { font-family: var(--mono); font-size: 11px; opacity: 0.6; }
108	
109	    .alpha-grid { display: grid; grid-template-columns: repeat(5, 1fr); padding: 0 24px; gap: 8px; }
110	    .alpha-btn { aspect-ratio: 1; display: grid; place-items: center; border: 1.5px solid var(--border-lt); border-radius: 6px; font-size: 14px; font-weight: 700; cursor: pointer; transition: all 0.2s; }
111	    .alpha-btn:hover { border-color: var(--fg); background: var(--surface); }
112	    .alpha-btn.active { background: var(--fg); color: var(--bg); border-color: var(--fg); }
113	
114	    /* Main Content */
115	    .main { padding: 60px; max-width: 1200px; margin: 0 auto; }
116	    .section-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 32px; }
117	    .section-title { font-family: var(--font-display); font-size: 32px; font-weight: 800; }
118	    
119	    .view-controls { display: flex; background: var(--surface); padding: 4px; border-radius: var(--radius); border: 1.5px solid var(--border-lt); }
120	    .view-btn { padding: 8px 16px; border: none; background: none; border-radius: 6px; cursor: pointer; display: flex; align-items: center; gap: 8px; font-weight: 700; color: var(--muted); transition: all 0.2s; }
121	    .view-btn.active { background: var(--bg); color: var(--fg); box-shadow: var(--shadow-sm); }
122	
123	    /* Card Grid */
124	    .term-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(340px, 1fr)); gap: 32px; }
125	    .term-card {
126	      background: var(--bg); border: 1.5px solid var(--border-lt); border-radius: 12px; padding: 32px;
127	      transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1); cursor: pointer; position: relative;
128	      display: flex; flex-direction: column; height: 100%;
129	    }
130	    .term-card:hover { border-color: var(--accent); box-shadow: var(--shadow-md); transform: translateY(-6px); }
131	    
132	    .card-top { display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 20px; }
133	    .cat-badge { padding: 4px 10px; font-size: 11px; font-weight: 800; border-radius: 4px; text-transform: uppercase; letter-spacing: 0.05em; }
134	    .badge-privacy { background: oklch(95% 0.05 250); color: oklch(40% 0.15 250); }
135	    .badge-security { background: oklch(95% 0.05 45); color: oklch(40% 0.15 45); }
136	    .badge-infra { background: oklch(95% 0.05 150); color: oklch(40% 0.15 150); }
137	    .badge-compliance { background: oklch(95% 0.05 300); color: oklch(40% 0.15 300); }
138	    .badge-data { background: oklch(95% 0.05 0); color: oklch(40% 0.15 0); }
139	    
140	    .mcp-icon { font-size: 18px; color: var(--accent); }
141	    
142	    .card-title { font-family: var(--font-display); font-size: 28px; font-weight: 800; margin-bottom: 8px; transition: color 0.2s; line-height: 1.2; }
143	    .card-subtitle { font-family: var(--mono); font-size: 14px; color: var(--muted); margin-bottom: 20px; font-weight: 500; }
144	    .card-desc { font-size: 15px; color: var(--fg-soft); line-height: 1.6; margin-bottom: 24px; flex-grow: 1; display: -webkit-box; -webkit-line-clamp: 3; -webkit-box-orient: vertical; overflow: hidden; }
145	    
146	    .card-footer { display: flex; flex-wrap: wrap; gap: 8px; padding-top: 20px; border-top: 1px solid var(--border-lt); }
147	    .tag { font-size: 12px; font-weight: 600; color: var(--muted); background: var(--surface); padding: 2px 10px; border-radius: 4px; border: 1px solid var(--border-lt); }
148	
149	    /* ag-Grid Theme Override */
150	    #gridWrap { height: 700px; border-radius: 12px; overflow: hidden; border: 1.5px solid var(--border-lt); box-shadow: var(--shadow-sm); }
151	    .ag-theme-balham-atlas {
152	      --ag-background-color: var(--bg);
153	      --ag-header-background-color: var(--surface);
154	      --ag-row-hover-color: var(--accent-soft);
155	      --ag-selected-row-color: var(--accent-soft);
156	      --ag-border-color: var(--border-lt);
157	      --ag-header-foreground-color: var(--muted);
158	      --ag-foreground-color: var(--fg);
159	      --ag-font-family: var(--font);
160	      --ag-font-size: 15px;
161	      --ag-header-height: 56px;
162	      --ag-row-height: 72px;
163	    }
164	
165	    .sync-footer { margin-top: 100px; padding: 60px 0; border-top: 1.5px solid var(--border-lt); color: var(--muted); font-size: 14px; display: flex; justify-content: space-between; }
166	
167	    /* Responsive */
168	    @media (max-width: 1024px) {
169	      .layout { grid-template-columns: 1fr; }
170	      .sidebar { display: none; }
171	      .hero { padding: 60px 24px; }
172	      .hero h1 { font-size: 40px; }
173	      .main { padding: 40px 24px; }
174	    }
175	  </style>
176	</head>
177	<body>
178	  <nav class="nav">
179	    <a href="index.html" class="nav-logo">Term<span>Base</span> Atlas</a>
180	    <div class="nav-links">
181	      <a href="index.html" class="nav-link active">용어사전</a>
182	      <a href="forbidden-words.html" class="nav-link">금칙어 관리</a>
183	      <a href="admin/index.html" class="nav-link" style="font-size: 12px; opacity: 0.6;">Admin Console</a>
184	    </div>
185	    <div class="nav-actions">
186	      <button class="theme-toggle" id="themeToggle">
187	        <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z"></path></svg>
188	      </button>
189	    </div>
190	  </nav>
191	
192	  <section class="hero">
193	    <h1>지식의 좌표를 찾다</h1>
194	    <p>행정안전부 표준 용어를 기반으로 설계된 전문 용어사전. AI 에이전트와 연동 가능한 MCP 생태계의 핵심 데이터를 탐색하세요.</p>
195	    <div class="search-hero-wrap">
196	      <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line></svg>
197	      <input type="search" id="heroSearch" placeholder="용어명, 영문명, 태그 또는 초성으로 검색...">
198	    </div>
199	  </section>
200	
201	  <div class="layout">
202	    <aside class="sidebar">
203	      <div class="sidebar-section">
204	        <div class="sidebar-title">Categories</div>
205	        <div id="catList">
206	          <div class="cat-item active" data-cat="all"><span>전체</span><span class="cat-count" id="cnt-all">0</span></div>
207	          <div class="cat-item" data-cat="privacy"><span>개인정보 보호</span><span class="cat-count" id="cnt-privacy">0</span></div>
208	          <div class="cat-item" data-cat="security"><span>보안</span><span class="cat-count" id="cnt-security">0</span></div>
209	          <div class="cat-item" data-cat="infra"><span>인프라</span><span class="cat-count" id="cnt-infra">0</span></div>
210	          <div class="cat-item" data-cat="compliance"><span>규정 준수</span><span class="cat-count" id="cnt-compliance">0</span></div>
211	          <div class="cat-item" data-cat="data"><span>데이터 관리</span><span class="cat-count" id="cnt-data">0</span></div>
212	        </div>
213	      </div>
214	      <div class="sidebar-section">
215	        <div class="sidebar-title">Index</div>
216	        <div class="alpha-grid" id="alphaGrid">
217	          <!-- JS -->
218	        </div>
219	      </div>
220	    </aside>
221	
222	    <main class="main">
223	      <header class="section-header">
224	        <div class="section-title"><span id="visCount">0</span>개의 용어</div>
225	        <div class="view-controls">
226	          <button class="view-btn active" data-v="card">Grid</button>
227	          <button class="view-btn" data-v="table">Table</button>
228	        </div>
229	      </header>
230	
231	      <div id="cardWrap">
232	        <div class="term-grid" id="termGrid">
233	          <!-- JS -->
234	        </div>
235	      </div>
236	
237	      <div id="gridWrap" style="display: none;">
238	        <div id="myGrid" class="ag-theme-balham-atlas" style="height: 100%; width: 100%;"></div>
239	      </div>
240	
241	      <footer class="sync-footer">
242	        <div>© 2026 TermBase Atlas · Editorial Style</div>
243	        <div>동기화: 2026-05-26 08:30 (행안부 API)</div>
244	      </footer>
245	    </main>
246	  </div>
247	
248	  <script>
249	    const TERMS = [
250	      { id:'pseudonymization', name:'가명처리', nameEn:'Pseudonymization', category:'privacy', def:'개인정보를 가명으로 처리하여 원래의 상태로 복원하기 위한 추가 정보의 사용·결합 없이 특정 개인을 알아볼 수 없도록 하는 처리.', tags:['개인정보보호법','ISMS-P'], mcp: true },
251	      { id:'anonymization', name:'비식별화', nameEn:'Anonymization', category:'privacy', def:'개인을 식별할 수 없도록 개인정보를 처리하는 기술 및 관리적 조치. 재식별 불가능 상태를 목표로 함.', tags:['ISO 29101','GDPR'], mcp: true },
252	      { id:'data-subject', name:'정보주체', nameEn:'Data Subject', category:'privacy', def:'처리되는 개인정보에 의해 식별되거나 식별 가능한 살아 있는 자연인.', tags:['데이터 권리','GDPR'], mcp: true },
253	      { id:'dpia', name:'개인정보 영향평가', nameEn:'DPIA', category:'privacy', def:'정보시스템의 구축·변경 시 개인정보 보호에 미칠 영향을 미리 분석하고 위험요인을 개선하는 절차.', tags:['영향평가','의무사항'], mcp: true },
254	      { id:'encryption', name:'암호화', nameEn:'Encryption', category:'security', def:'평문을 암호문으로 변환하는 과정. AES-256, RSA 등 알고리즘으로 데이터 기밀성을 보장.', tags:['기밀성','KISA'], mcp: true },
255	      { id:'zero-trust', name:'제로트러스트', nameEn:'Zero Trust', category:'security', def:'"신뢰하지 않고 항상 검증"이라는 원칙에 기반한 보안 모델. 네트워크 경계 없이 모든 접근을 인증·인가.', tags:['ZTNA','보안모델'], mcp: true },
256	      { id:'container', name:'컨테이너', nameEn:'Container', category:'infra', def:'애플리케이션과 의존성을 격리된 단위로 패키징하는 기술. Docker, containerd 등이 구현체.', tags:['Docker','Cloud'], mcp: false },
257	      { id:'isms-p', name:'ISMS-P', nameEn:'ISMS-P Certification', category:'compliance', def:'정보보호 관리체계(ISMS)와 개인정보보호 관리체계(PIMS)를 통합한 한국 인증 제도.', tags:['국내인증','KISA'], mcp: true },
258	      { id:'data-lineage', name:'데이터 리니지', nameEn:'Data Lineage', category:'data', def:'데이터의 출처에서 소비까지 이동 경로와 변환 이력을 추적하는 기능. 감사 대응 및 품질 관리에 핵심.', tags:['데이터거버넌스','Apache Atlas'], mcp: false },
259	      { id:'data-masking', name:'데이터 마스킹', nameEn:'Data Masking', category:'data', def:'민감 데이터를 가상의 값으로 대체하여 비프로덕션 환경에서 실데이터 노출을 방지하는 기술.', tags:['동적마스킹','보안'], mcp: true }
260	    ];
261	
262	    const ONSETS = ['ㄱ','ㄲ','ㄴ','ㄷ','ㄸ','ㄹ','ㅁ','ㅂ','ㅃ','ㅅ','ㅆ','ㅇ','ㅈ','ㅉ','ㅊ','ㅋ','ㅌ','ㅍ','ㅎ'];
263	    const CAT_LABELS = { all:'전체', privacy:'개인정보 보호', security:'보안', infra:'인프라', compliance:'규정 준수', data:'데이터 관리' };
264	
265	    let currentView = localStorage.getItem('termbase:view') || 'card';
266	    let theme = localStorage.getItem('termbase:theme') || 'light';
267	    let activeCat = 'all';
268	    let query = '';
269	    let gridApi = null;
270	
271	    // Theme Logic
272	    function applyTheme() {
273	      document.documentElement.setAttribute('data-theme', theme);
274	      document.querySelector('#themeToggle svg path').setAttribute('d', theme === 'dark' ? 'M12 3v1m0 16v1m9-9h-1M4 12H3m15.364 6.364l-.707-.707M6.343 6.343l-.707-.707m12.728 0l-.707.707M6.343 17.657l-.707.707M16 12a4 4 0 11-8 0 4 4 0 018 0z' : 'M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z');
275	    }
276	    document.getElementById('themeToggle').onclick = () => { theme = theme === 'light' ? 'dark' : 'light'; localStorage.setItem('termbase:theme', theme); applyTheme(); };
277	
278	    // Search & Filter
279	    function getChoseong(str) {
280	      let res = "";
281	      for (let i = 0; i < str.length; i++) {
282	        const code = str.charCodeAt(i) - 44032;
283	        if (code > -1 && code < 11172) res += ONSETS[Math.floor(code / 588)];
284	        else res += str.charAt(i);
285	      }
286	      return res;
287	    }
288	
289	    function filtered() {
290	      return TERMS.filter(t => {
291	        if (activeCat !== 'all' && t.category !== activeCat) return false;
292	        if (!query) return true;
293	        const q = query.toLowerCase();
294	        return t.name.includes(q) || t.nameEn.toLowerCase().includes(q) || getChoseong(t.name).includes(q) || t.tags.some(tg => tg.includes(q));
295	      });
296	    }
297	
298	    function render() {
299	      const data = filtered();
300	      document.getElementById('visCount').textContent = data.length;
301	      document.getElementById('cnt-all').textContent = TERMS.length;
302	      Object.keys(CAT_LABELS).forEach(c => { if(c !== 'all') document.getElementById(`cnt-${c}`).textContent = TERMS.filter(t => t.category === c).length; });
303	
304	      if (currentView === 'card') {
305	        document.getElementById('termGrid').innerHTML = data.map(t => `
306	          <div class="term-card" onclick="location.href='term-detail.html?id=${t.id}'">
307	            <div class="card-top">
308	              <span class="cat-badge badge-${t.category}">${CAT_LABELS[t.category]}</span>
