216	      { word: '비밀번호', severity: 'critical', reason: '보안 가이드라인 위반. 패스워드는 어떠한 형태의 로그나 텍스트로도 남지 않아야 합니다.', alts: '인증토큰' },
217	      { word: '계좌번호', severity: 'warning', reason: '금융정보 보안 위험. 필요 시 마스킹 처리를 권고합니다.', alts: '결제ID' },
218	      { word: '바보', severity: 'warning', reason: '사용자 불쾌감 유발 및 CS 품질 저해 표현.', alts: '순화어' }
219	    ];
220	
221	    const input = document.getElementById('scanInput');
222	    const backdrop = document.getElementById('scanBackdrop');
223	    const vList = document.getElementById('violationList');
224	    const metrics = document.getElementById('scanMetrics');
225	
226	    function updateScanner() {
227	      const text = input.value;
228	      let html = text.replace(/[&<>"']/g, m => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":"&#39;"}[m]));
229	      
230	      const detected = [];
231	      DATA.forEach(item => {
232	        if (text.includes(item.word)) {
233	          detected.push(item);
234	          const regex = new RegExp(item.word, 'gi');
235	          html = html.replace(regex, `<mark class="hl-${item.severity}">${item.word}</mark>`);
236	        }
237	      });
238	
239	      backdrop.innerHTML = html + (text.endsWith('\n') ? ' ' : '');
240	      metrics.textContent = `CHAR_COUNT: ${text.length} · VIOLATIONS: ${detected.length}`;
241	
242	      if (detected.length > 0) {
243	        vList.innerHTML = detected.map(d => `
244	          <div class="violation-item">
245	            <div class="v-word" style="color: var(--${d.severity})">${d.word}</div>
246	            <div class="v-reason">${d.reason}</div>
247	          </div>
248	        `).join('');
249	      } else {
250	        vList.innerHTML = `<div style="color: var(--muted); text-align: center; margin-top: 40px; font-size: 14px;">위반 사항 없음</div>`;
251	      }
252	    }
253	
254	    input.onscroll = () => backdrop.scrollTop = input.scrollTop;
255	    input.oninput = updateScanner;
256	
257	    document.getElementById('inventoryBody').innerHTML = DATA.map(d => `
258	      <tr>
259	        <td><span class="sev-tag sev-${d.severity}">${d.severity}</span></td>
260	        <td style="font-family: var(--font-display); font-size: 20px; font-weight: 800;">${d.word}</td>
261	        <td style="font-size: 14px; color: var(--fg-soft); line-height: 1.6;">${d.reason}</td>
262	        <td style="font-family: var(--mono); font-weight: 700; color: var(--accent);">${d.alts}</td>
263	      </tr>
264	    `).join('');
265	
266	    let theme = 'light';
267	    document.getElementById('themeToggle').onclick = () => {
268	      theme = theme === 'light' ? 'dark' : 'light';
269	      document.documentElement.setAttribute('data-theme', theme);
270	    };
271	  </script>
