249	  <script>
250	    const TERMS = [
251	      { id:'pseudonymization', name:'가명처리', nameEn:'Pseudonymization', category:'privacy', def:'개인정보를 가명으로 처리하여 원래의 상태로 복원하기 위한 추가 정보의 사용·결합 없이 특정 개인을 알아볼 수 없도록 하는 처리.', tags:['개인정보보호법','ISMS-P'], mcp: true },
252	      { id:'anonymization', name:'비식별화', nameEn:'Anonymization', category:'privacy', def:'개인을 식별할 수 없도록 개인정보를 처리하는 기술 및 관리적 조치. 재식별 불가능 상태를 목표로 함.', tags:['ISO 29101','GDPR'], mcp: true },
253	      { id:'data-subject', name:'정보주체', nameEn:'Data Subject', category:'privacy', def:'처리되는 개인정보에 의해 식별되거나 식별 가능한 살아 있는 자연인.', tags:['데이터 권리','GDPR'], mcp: true },
254	      { id:'dpia', name:'개인정보 영향평가', nameEn:'DPIA', category:'privacy', def:'정보시스템의 구축·변경 시 개인정보 보호에 미칠 영향을 미리 분석하고 위험요인을 개선하는 절차.', tags:['영향평가','의무사항'], mcp: true },
255	      { id:'encryption', name:'암호화', nameEn:'Encryption', category:'security', def:'평문을 암호문으로 변환하는 과정. AES-256, RSA 등 알고리즘으로 데이터 기밀성을 보장.', tags:['기밀성','KISA'], mcp: true },
256	      { id:'zero-trust', name:'제로트러스트', nameEn:'Zero Trust', category:'security', def:'"신뢰하지 않고 항상 검증"이라는 원칙에 기반한 보안 모델. 네트워크 경계 없이 모든 접근을 인증·인가.', tags:['ZTNA','보안모델'], mcp: true },
257	      { id:'container', name:'컨테이너', nameEn:'Container', category:'infra', def:'애플리케이션과 의존성을 격리된 단위로 패키징하는 기술. Docker, containerd 등이 구현체.', tags:['Docker','Cloud'], mcp: false },
258	      { id:'isms-p', name:'ISMS-P', nameEn:'ISMS-P Certification', category:'compliance', def:'정보보호 관리체계(ISMS)와 개인정보보호 관리체계(PIMS)를 통합한 한국 인증 제도.', tags:['국내인증','KISA'], mcp: true },
259	      { id:'data-lineage', name:'데이터 리니지', nameEn:'Data Lineage', category:'data', def:'데이터의 출처에서 소비까지 이동 경로와 변환 이력을 추적하는 기능. 감사 대응 및 품질 관리에 핵심.', tags:['데이터거버넌스','Apache Atlas'], mcp: false },
260	      { id:'data-masking', name:'데이터 마스킹', nameEn:'Data Masking', category:'data', def:'민감 데이터를 가상의 값으로 대체하여 비프로덕션 환경에서 실데이터 노출을 방지하는 기술.', tags:['동적마스킹','보안'], mcp: true }
261	    ];
262	
263	    const ONSETS = ['ㄱ','ㄲ','ㄴ','ㄷ','ㄸ','ㄹ','ㅁ','ㅂ','ㅃ','ㅅ','ㅆ','ㅇ','ㅈ','ㅉ','ㅊ','ㅋ','ㅌ','ㅍ','ㅎ'];
264	    const CAT_LABELS = { all:'전체', privacy:'개인정보 보호', security:'보안', infra:'인프라', compliance:'규정 준수', data:'데이터 관리' };
265	
266	    let currentView = localStorage.getItem('termbase:view') || 'card';
267	    let theme = localStorage.getItem('termbase:theme') || 'light';
268	    let activeCat = 'all';
269	    let query = '';
270	    let gridApi = null;
271	
272	    // Theme Logic
273	    function applyTheme() {
274	      document.documentElement.setAttribute('data-theme', theme);
275	      document.querySelector('#themeToggle svg path').setAttribute('d', theme === 'dark' ? 'M12 3v1m0 16v1m9-9h-1M4 12H3m15.364 6.364l-.707-.707M6.343 6.343l-.707-.707m12.728 0l-.707.707M6.343 17.657l-.707.707M16 12a4 4 0 11-8 0 4 4 0 018 0z' : 'M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z');
276	    }
277	    document.getElementById('themeToggle').onclick = () => { theme = theme === 'light' ? 'dark' : 'light'; localStorage.setItem('termbase:theme', theme); applyTheme(); };
278	
279	    // Search & Filter
280	    function getChoseong(str) {
281	      let res = "";
282	      for (let i = 0; i < str.length; i++) {
283	        const code = str.charCodeAt(i) - 44032;
284	        if (code > -1 && code < 11172) res += ONSETS[Math.floor(code / 588)];
285	        else res += str.charAt(i);
286	      }
287	      return res;
288	    }
289	
290	    function filtered() {
291	      return TERMS.filter(t => {
292	        if (activeCat !== 'all' && t.category !== activeCat) return false;
293	        if (!query) return true;
294	        const q = query.toLowerCase();
295	        return t.name.includes(q) || t.nameEn.toLowerCase().includes(q) || getChoseong(t.name).includes(q) || t.tags.some(tg => tg.includes(q));
296	      });
297	    }
298	
299	    function render() {
300	      const data = filtered();
301	      document.getElementById('visCount').textContent = data.length;
302	      document.getElementById('cnt-all').textContent = TERMS.length;
303	      Object.keys(CAT_LABELS).forEach(c => { if(c !== 'all') document.getElementById(`cnt-${c}`).textContent = TERMS.filter(t => t.category === c).length; });
304	
305	      if (currentView === 'card') {
306	        document.getElementById('termGrid').innerHTML = data.map(t => `
307	          <div class="term-card" onclick="location.href='term-detail.html?id=${t.id}'">
308	            <div class="card-top">
309	              <span class="cat-badge badge-${t.category}">${CAT_LABELS[t.category]}</span>
310	              ${t.mcp ? '<span class="mcp-icon" title="MCP Tool 사용 가능">⚡</span>' : ''}
311	            </div>
312	            <div class="card-title">${t.name}</div>
313	            <div class="card-subtitle">${t.nameEn}</div>
314	            <div class="card-desc">${t.def}</div>
315	            <div class="card-footer">${t.tags.map(tg => `<span class="tag">${tg}</span>`).join('')}</div>
316	          </div>
317	        `).join('');
318	      } else if (gridApi) {
319	        gridApi.setGridOption('rowData', data);
320	      }
321	    }
322	
323	    // Init Alpha
324	    const alphaGrid = document.getElementById('alphaGrid');
325	    [...ONSETS, 'ABC'].forEach(char => {
326	      const btn = document.createElement('div'); btn.className = 'alpha-btn'; btn.textContent = char;
327	      btn.onclick = () => { btn.classList.toggle('active'); query = btn.classList.contains('active') ? char : ''; render(); };
328	      alphaGrid.appendChild(btn);
329	    });
330	
331	    // View Toggle
332	    document.querySelectorAll('.view-btn').forEach(btn => {
333	      btn.onclick = () => {
334	        currentView = btn.dataset.v; localStorage.setItem('termbase:view', currentView);
335	        document.querySelectorAll('.view-btn').forEach(b => b.classList.toggle('active', b === btn));
336	        document.getElementById('cardWrap').style.display = currentView === 'card' ? 'block' : 'none';
337	        document.getElementById('gridWrap').style.display = currentView === 'table' ? 'block' : 'none';
338	        if (currentView === 'table' && !gridApi) {
339	          gridApi = agGrid.createGrid(document.getElementById('myGrid'), {
340	            columnDefs: [
341	              { field: 'name', headerName: '용어명', flex: 1.5 },
342	              { field: 'nameEn', headerName: '영문명', flex: 1 },
343	              { field: 'category', headerName: '분류', valueFormatter: p => CAT_LABELS[p.value], width: 140 },
344	              { field: 'def', headerName: '정의', flex: 3 },
345	            ],
346	            rowData: filtered(),
347	            onRowClicked: (e) => location.href = `term-detail.html?id=${e.data.id}`
348	          });
349	        }
350	        render();
351	      };
352	    });
353	
354	    document.getElementById('heroSearch').oninput = (e) => { query = e.target.value; render(); };
355	    document.querySelectorAll('.cat-item').forEach(item => { item.onclick = () => { activeCat = item.dataset.cat; document.querySelectorAll('.cat-item').forEach(i => i.classList.toggle('active', i === item)); render(); }; });
356	
357	    applyTheme();
358	    if(currentView === 'table') document.querySelector('[data-v="table"]').click();
359	    else render();
360	  </script>
