187	// 테마 전환
188	function toggleTheme() {
189	  const current = document.documentElement.getAttribute('data-theme');
190	  const target = current === 'dark' ? 'light' : 'dark';
191	  document.documentElement.setAttribute('data-theme', target);
192	  localStorage.setItem('admin-theme', target);
193	}
194	if (localStorage.getItem('admin-theme') === 'dark') {
195	  document.documentElement.setAttribute('data-theme', 'dark');
196	}
197	
198	// 탭 전환
199	const tabMap = { sync:'tab-sync', import:'tab-import', history:'tab-history', pending:'tab-pending' };
200	function switchTab(id) {
201	  document.querySelectorAll('.tab-btn').forEach((b,i) => b.classList.toggle('active', ['sync','import','history','pending'][i]===id));
202	  Object.values(tabMap).forEach(p => document.getElementById(p).classList.remove('active'));
203	  document.getElementById(tabMap[id]).classList.add('active');
204	}
205	
206	// 마지막 동기화 시각
207	document.getElementById('lastSyncTime').textContent = new Date(MOCK.stats.lastSync).toLocaleString('ko-KR');
208	document.getElementById('pendingBadge').textContent = MOCK.pendingTerms.length;
209	
210	// 동기화 시뮬레이션
211	function doSync() {
212	  const btn = document.getElementById('syncBtn');
213	  const st  = document.getElementById('syncStatus');
214	  btn.disabled = true; btn.textContent = '동기화 중…';
215	  st.textContent = '행안부 API 호출 중…';
216	  setTimeout(() => {
217	    document.getElementById('lastSyncTime').textContent = new Date().toLocaleString('ko-KR');
218	    btn.disabled = false; btn.textContent = '지금 동기화';
219	    st.textContent = '완료: +0개 변경';
220	    setTimeout(() => { st.textContent=''; }, 3000);
221	  }, 2000);
222	}
223	
224	// 변경 이력 테이블
225	function renderHistory() {
226	  const htb = document.getElementById('historyTable');
227	  htb.innerHTML = '';
228	  MOCK.changeLog.forEach(r => {
229	    const tr = document.createElement('tr');
230	    tr.innerHTML = `<td class="mono">${r.ts}</td><td>${r.action}</td><td>${r.detail}</td><td class="mono">${r.user}</td>`;
231	    htb.appendChild(tr);
232	  });
233	}
234	renderHistory();
235	
236	// 검수 대기 목록
237	let pendingData = [...MOCK.pendingTerms];
238	function renderPending() {
239	  const list = document.getElementById('pendingList');
240	  const empty = document.getElementById('pendingEmpty');
241	  list.innerHTML = '';
242	  if (pendingData.length === 0) { empty.style.display = 'block'; return; }
243	  empty.style.display = 'none';
244	  pendingData.forEach(p => {
245	    const el = document.createElement('div');
246	    el.className = 'pending-card';
247	    el.innerHTML = `
248	      <div>
249	        <div class="pname">${p.name} <span style="font-size:12px;color:var(--muted);font-weight:400;">${p.nameEn}</span></div>
250	        <div class="pmeta">${p.category} · 제출자: ${p.submittedBy} · ${p.submittedAt}</div>
251	      </div>
252	      <div class="pending-actions">
253	        <button class="btn btn-outline" onclick="rejectTerm('${p.id}')">반려</button>
254	        <button class="btn btn-primary" onclick="approveTerm('${p.id}')">승인</button>
255	      </div>
256	    `;
257	    list.appendChild(el);
258	  });
259	}
260	function approveTerm(id) {
261	  pendingData = pendingData.filter(p => p.id !== id);
262	  document.getElementById('pendingBadge').textContent = pendingData.length;
263	  renderPending();
264	}
265	function rejectTerm(id) {
266	  pendingData = pendingData.filter(p => p.id !== id);
267	  document.getElementById('pendingBadge').textContent = pendingData.length;
268	  renderPending();
269	}
270	renderPending();
271	
272	// 파일 가져오기 (CSV/JSON 시뮬레이션)
273	function handleFile(e) {
274	  const file = e.target.files ? e.target.files[0] : (e.dataTransfer ? e.dataTransfer.files[0] : null);
275	  if (!file) return;
276	
277	  const dz = document.getElementById('dropZone');
278	  const originalHtml = dz.innerHTML;
279	  
280	  // 업로드 시뮬레이션
281	  let progress = 0;
282	  dz.onclick = null; // 클릭 방지
283	  const interval = setInterval(() => {
284	    progress += Math.random() * 30;
285	    if (progress >= 100) {
286	      progress = 100;
287	      clearInterval(interval);
288	      finalizePreview(file);
289	      dz.innerHTML = originalHtml;
290	      dz.onclick = () => document.getElementById('fileInput').click();
291	    }
292	    dz.innerHTML = `<div style="width:100%; max-width:300px; height:8px; background:var(--border-light); margin:20px auto; border-radius:4px; overflow:hidden;">
293	      <div style="width:${progress}%; height:100%; background:var(--accent); transition: width 0.1s;"></div>
294	    </div>
295	    <div style="font-size:12px; font-weight:600;">파일 분석 중... ${Math.floor(progress)}%</div>`;
296	  }, 150);
297	}
298	
299	function finalizePreview(file) {
300	  const rows = [
301	    { name:'데이터 주체', nameEn:'Data Subject', category:'개인정보 보호', definition:'개인정보의 처리로부터 보호받아야 할 식별 가능한 개인' },
302	    { name:'처리자',       nameEn:'Processor',    category:'개인정보 보호', definition:'개인정보처리자를 위하여 개인정보를 처리하는 자연인·법인 등' },
303	    { name:'개인정보파일', nameEn:'Personal Information File', category:'개인정보 보호', definition:'개인정보를 쉽게 검색할 수 있도록 일정한 규칙에 따라 체계적으로 배열하거나 구성한 개인정보의 집합물' },
304	  ];
305	  
306	  document.getElementById('previewCount').textContent = rows.length;
307	  const tb = document.querySelector('#previewTable tbody');
308	  tb.innerHTML = '';
309	  rows.forEach(r => {
310	    const tr = document.createElement('tr');
311	    tr.innerHTML = `<td>${r.name}</td><td class="mono">${r.nameEn}</td><td>${r.category}</td><td style="max-width:300px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${r.definition.slice(0,50)}</td>`;
312	    tb.appendChild(tr);
313	  });
314	  document.getElementById('previewSection').style.display = 'block';
315	}
316	
317	function cancelImport() {
318	  document.getElementById('previewSection').style.display = 'none';
319	  document.getElementById('fileInput').value = '';
320	}
321	
322	function confirmImport() {
323	  const count = document.getElementById('previewCount').textContent;
324	  alert(`가져오기 완료 (목업): ${count}개 용어가 검수 대기 큐에 추가됐습니다.`);
325	  
326	  // 변경 이력에 추가 시뮬레이션
327	  const newLog = {
328	    ts: new Date().toISOString().replace('T', ' ').slice(0, 19),
329	    action: '가져오기',
330	    detail: `CSV 파일을 통해 ${count}개 용어 추가`,
331	    user: 'admin'
332	  };
333	  MOCK.changeLog.unshift(newLog);
334	  renderHistory();
335	  
336	  cancelImport();
337	}
338	
339	// 드래그 앤 드롭
340	const dz = document.getElementById('dropZone');
341	dz.addEventListener('dragover', e => { e.preventDefault(); dz.classList.add('drag-over'); });
342	dz.addEventListener('dragleave', () => dz.classList.remove('drag-over'));
343	dz.addEventListener('drop', e => { e.preventDefault(); dz.classList.remove('drag-over'); handleFile({dataTransfer:e.dataTransfer}); });
344	</script>
