169	// API 키 로드/저장
170	let keys = JSON.parse(localStorage.getItem('tb-api-keys')) || [...MOCK.apiKeys];
171	
172	function saveKeys() {
173	  localStorage.setItem('tb-api-keys', JSON.stringify(keys));
174	}
175	
176	function renderKeys() {
177	  const tb = document.getElementById('keyTable');
178	  tb.innerHTML = '';
179	  keys.forEach(k => {
180	    const revoked = k.status === 'revoked';
181	    const tr = document.createElement('tr');
182	    tr.innerHTML = `
183	      <td class="${revoked?'revoked':''}" style="font-weight:500">${k.name}</td>
184	      <td class="mono">${k.created}</td>
185	      <td class="mono">${k.lastUsed}</td>
186	      <td><span class="badge ${revoked?'badge-err':'badge-ok'}">${revoked?'폐기됨':'활성'}</span></td>
187	      <td style="text-align:right">
188	        ${revoked ? '' : `<button class="btn btn-outline" style="font-size:11px;padding:4px 10px;" onclick="revokeKey('${k.id}')">폐기</button>`}
189	      </td>
190	    `;
191	    tb.appendChild(tr);
192	  });
193	}
194	renderKeys();
195	
196	function generateKey() {
197	  const name = document.getElementById('newKeyName').value.trim();
198	  if (!name) { alert('키 이름을 입력하세요.'); return; }
199	  const newKey = { id: 'k-' + Date.now(), name, created: new Date().toISOString().slice(0,10), lastUsed: '—', status: 'active' };
200	  keys.unshift(newKey);
201	  saveKeys();
202	  renderKeys();
203	  const fakeToken = 'tb_' + Math.random().toString(36).slice(2,34);
204	  document.getElementById('newKeyValue').textContent = fakeToken;
205	  document.getElementById('newKeyAlert').style.display = 'block';
206	  document.getElementById('newKeyName').value = '';
207	}
208	
209	function copyKey() {
210	  const val = document.getElementById('newKeyValue').textContent;
211	  navigator.clipboard.writeText(val).then(() => {
212	    const btn = document.querySelector('#newKeyAlert .btn');
213	    const originalText = btn.textContent;
214	    btn.textContent = '복사됨!';
215	    setTimeout(() => btn.textContent = originalText, 2000);
216	  });
217	}
218	
219	function revokeKey(id) {
220	  if (!confirm('이 키를 폐기하면 연결된 클라이언트가 인증 오류를 받게 됩니다. 계속하시겠습니까?')) return;
221	  keys = keys.map(k => k.id === id ? {...k, status:'revoked'} : k);
222	  saveKeys();
223	  renderKeys();
224	}
225	
226	function saveSettings() {
227	  const msg = document.getElementById('saveMsg');
228	  msg.textContent = '저장됨 (목업)';
229	  setTimeout(() => { msg.textContent = ''; }, 2000);
230	}
231	</script>
