25	
26	/**
27	 * @param {import('react').ReactNode} element
28	 * @returns {JSX.Element}
29	 */
30	const withSuspense = (element) => <Suspense fallback={loadingFallback}>{element}</Suspense>;
31	
32	export const router = createBrowserRouter([
33	    {
